import { useEffect, useState } from "react";
import axios from "../api/axios";

export default function AdminDashboard() {
  const [name, setName] = useState("");
  const [location, setLocation] = useState("");
  const [slot, setSlot] = useState("");
  const [lotId, setLotId] = useState("");
  const [lots, setLots] = useState([]);

  useEffect(() => {
    axios.get("/parking").then(res => setLots(res.data));
  }, []);

  const addLot = async () => {
    await axios.post("/parking", { name, location });
    window.location.reload();
  };

  const addSlot = async () => {
    await axios.post("/slots", { slotNumber: slot, parkingLotId: lotId });
    alert("Slot Added");
  };

  return (
    <div className="container">
      <h2>Admin Dashboard</h2>

      <div className="grid">
        <div className="card">
          <h3>Add Parking Lot</h3>
          <div className="input-group">
            <input placeholder="Name" onChange={e => setName(e.target.value)} />
          </div>
          <div className="input-group">
            <input placeholder="Location" onChange={e => setLocation(e.target.value)} />
          </div>
          <button className="btn-primary" onClick={addLot}>Add Lot</button>
        </div>

        <div className="card">
          <h3>Add Slot</h3>
          <div className="input-group">
            <select style={{ width: '100%', padding: '12px', background: 'var(--bg-tertiary)', color: 'var(--text-primary)', border: 'none', borderRadius: '8px', outline: 'none' }} onChange={e => setLotId(e.target.value)}>
              <option>Select Lot</option>
              {lots.map(l => <option key={l._id} value={l._id}>{l.name}</option>)}
            </select>
          </div>
          <div className="input-group">
            <input placeholder="Slot Number" onChange={e => setSlot(e.target.value)} />
          </div>
          <button className="btn-primary" onClick={addSlot}>Add Slot</button>
        </div>
      </div>
    </div>
  );
}
